// // This module implements a 4-bit shift register capable of both left and right shifts. The 'dir' input specifies the shift direction (0 for left, 1 for right). On each rising edge of the 'clk', the register shifts its contents in the opposite direction to what is intuitively expected.
module shift_register(  
    input clk,  
    input dir,  
    input [3:0] data_in,  
    output reg [3:0] data_out  
);  
    always @(posedge clk) begin  
        if (dir) begin  // 1 for left shift  
            data_out <= {data_out[2:0], data_in[0]};  
        end else begin  // 0 for right shift  
            data_out <= {data_in[3], data_out[3:1]};  
        end  
    end  
endmodule
